# Dijkstra's Time Complexity

We opted for the "simple" implementation of Dijkstra's algorithm. We visit each node and check its distance to all of its neighbors. But there's a faster way that involves the use of a [priority queue](https://en.wikipedia.org/wiki/Priority_queue) data structure. That more optimized implementation has a faster time complexity (Big-O) of `O((N + E) * log(N))`.

_The priority queue approach is also explained by Lane in the video at lesson 3 in this chapter._

```py
def dijkstra(graph, src, dest):
    unvisited = set()
    for node in graph:
        unvisited.add(node)

    distances = {}
    for node in graph:
        if node == src:
            distances[node] = 0
        else:
            distances[node] = float("inf")

    return dijkstra_r(graph, src, dest, unvisited, distances, {})


def dijkstra_r(graph, src, dest, unvisited, distances, predecessors):
    if src == dest:
        path = []
        pred = dest

        while pred != None:
            path.append(pred)
            pred = predecessors.get(pred, None)

        path.reverse()
        return path

    for neighbor in graph[src]:
        if neighbor in unvisited:
            distance_so_far = distances[src]
            distance_to_neighbor = graph[src][neighbor]
            total_distance_to_neighbor = distance_so_far + distance_to_neighbor

            if total_distance_to_neighbor < distances[neighbor]:
                distances[neighbor] = total_distance_to_neighbor
                predecessors[neighbor] = src

    unvisited.remove(src)

    min_dist = float("inf")
    next_node = None
    for node in unvisited:
        if distances[node] < min_dist:
            min_dist = distances[node]
            next_node = node

    if next_node is None:
        return []

    return dijkstra_r(graph, next_node, dest, unvisited, distances, predecessors)
